import { useEffect, useState } from "react";

interface DemoProps {}

export default function Demo(_props: DemoProps) {
  const [progress, setProgress] = useState(0);
  const [showContent, setShowContent] = useState(false);

  useEffect(() => {
    const duration = 3000; // 3 seconds
    const interval = 30; // update every 30ms
    const step = interval / duration;

    const timer = setInterval(() => {
      setProgress((prev) => {
        const next = Math.min(prev + step, 1);
        if (next >= 1) {
          clearInterval(timer);
          // Stay at 100% (demo mock - never auto-dismisses)
        }
        return next;
      });
    }, interval);

    return () => clearInterval(timer);
  }, []);

  const percent = Math.round(progress * 100);

  return (
    <div
      className="min-h-screen flex flex-col items-center justify-center max-w-md mx-auto relative overflow-hidden"
      style={{ backgroundColor: "#1A365D" }}
    >
      {/* 背景星星装饰 */}
      <span className="absolute top-12 left-10 text-lg opacity-20">⭐</span>
      <span className="absolute top-20 right-12 text-2xl opacity-15">🌟</span>
      <span className="absolute bottom-24 left-8 text-xl opacity-20">✨</span>
      <span className="absolute bottom-32 right-10 text-lg opacity-15">⭐</span>
      <span className="absolute top-1/3 left-4 text-sm opacity-25">✨</span>
      <span className="absolute top-2/3 right-6 text-lg opacity-15">🌟</span>
      <span className="absolute bottom-10 left-1/3 text-sm opacity-20">⭐</span>
      <span className="absolute top-10 left-1/2 text-sm opacity-15">✨</span>

      {/* 足球弹跳动画 */}
      <div className="text-7xl mb-6" style={{ animation: "bounce 0.8s ease-in-out infinite alternate" }}>
        ⚽
      </div>

      {/* 标题 */}
      <h1 className="text-2xl font-bold mb-2" style={{ color: "#FF6B35" }}>
        叫叫足球嘉年华
      </h1>
      <p className="text-sm mb-10" style={{ color: "#FFFFFF", opacity: 0.6 }}>
        精彩即将开启
      </p>

      {/* 进度条 */}
      <div className="w-64 h-2 rounded-full overflow-hidden" style={{ backgroundColor: "rgba(255,255,255,0.15)" }}>
        <div
          className="h-full rounded-full transition-all duration-100 ease-linear"
          style={{
            width: `${percent}%`,
            backgroundColor: "#FF6B35",
            boxShadow: "0 0 8px rgba(255,107,53,0.5)",
          }}
        />
      </div>

      {/* 加载文案 */}
      <p className="text-sm mt-4" style={{ color: "#FFFFFF", opacity: 0.5 }}>
        正在加载活动资源{percent}%
      </p>

      {/* 自定义 bounce 动画 */}
      <style>{`
        @keyframes bounce {
          from { transform: translateY(0); }
          to { transform: translateY(-16px); }
        }
      `}</style>
    </div>
  );
}

